-- 0252_gm_roster.sql
-- GM roster: the authoritative "who is the GM" per store, independent of whether
-- that person has a Hub account. Powers the org-chart placeholder name and the
-- account reconciliation (matched / no account / name mismatch). status is
-- named | open | in_training. Seeded from the ops roster sheet; re-runnable
-- (the admin importer upserts on store_number). Service-role gatekeeper.

create table if not exists gm_roster (
  store_number   text        primary key,
  store_name     text,
  gm_name        text,
  status         text        not null default 'named',
  gm_email       text,
  gm_cell        text,
  gm_birthday    text,
  hire_date      text,
  placement_date text,
  updated_by     uuid        references profiles(id) on delete set null,
  updated_at     timestamptz not null default now()
);

alter table gm_roster enable row level security;

on conflict (store_number) do update set
  store_name = excluded.store_name, gm_name = excluded.gm_name, status = excluded.status,
  gm_email = excluded.gm_email, gm_cell = excluded.gm_cell, gm_birthday = excluded.gm_birthday,
  hire_date = excluded.hire_date, placement_date = excluded.placement_date, updated_at = now();

notify pgrst, 'reload schema';
